import { forwardRef } from "react";
import {
  RadioGroup as AriaRadioGroup,
  type RadioGroupProps as AriaRadioGroupProps,
  RadioGroupStateContext,
} from "react-aria-components";

// Re-export context for use by child components (RadioItem, RadioButton, RadioButtonTile)
export { RadioGroupStateContext };

interface RadioGroupCustomProps {
  /**
   * The current selected value (controlled).
   * Pass the `value` string of the selected radio.
   */
  value?: string;

  /**
   * The default selected value (uncontrolled).
   * Pass the `value` string of the selected radio.
   */
  defaultValue?: string;

  /**
   * Handler called when the selection changes.
   * Receives the value of the newly selected radio.
   */
  onChange?: (value: string) => void;

  /**
   * Whether all radios in the group are disabled.
   * @default false
   */
  disabled?: boolean;

  /**
   * Whether the radio group is in an invalid/error state.
   * When true, all radios in the group show error styling.
   * @default false
   */
  invalid?: boolean;

  /**
   * Whether a selection is required.
   * @default false
   */
  required?: boolean;

  /**
   * Whether the radio group is read-only.
   * @default false
   */
  readOnly?: boolean;

  /**
   * The name of the radio group, used when submitting an HTML form.
   */
  name?: string;
}

// Props that we rename from HTML-style to React Aria's is-prefixed style
type RenamedAriaProps =
  | "isDisabled"
  | "isInvalid"
  | "isRequired"
  | "isReadOnly";

export interface RadioGroupProps
  extends
    Omit<AriaRadioGroupProps, keyof RadioGroupCustomProps | RenamedAriaProps>,
    RadioGroupCustomProps {}

/**
 * RadioGroup manages a collection of RadioButton or RadioItem components,
 * handling selection state, validation, and accessibility.
 *
 * @example
 * // Controlled
 * const [value, setValue] = useState('option1');
 *
 * <RadioGroup value={value} onChange={setValue} aria-label="Options">
 *   <RadioButton value="option1" label={{ children: "Option 1" }} />
 *   <RadioButton value="option2" label={{ children: "Option 2" }} />
 * </RadioGroup>
 *
 * @example
 * // Uncontrolled
 * <RadioGroup defaultValue="option1" aria-label="Options">
 *   <RadioButton value="option1" label={{ children: "Option 1" }} />
 *   <RadioButton value="option2" label={{ children: "Option 2" }} />
 * </RadioGroup>
 *
 * @example
 * // With validation error
 * <RadioGroup invalid aria-label="Options">
 *   <RadioButton value="option1" label={{ children: "Option 1" }} />
 * </RadioGroup>
 */
export const RadioGroup = forwardRef<HTMLDivElement, RadioGroupProps>(
  ({ disabled, invalid, required, readOnly, ...props }, ref) => {
    return (
      <AriaRadioGroup
        ref={ref}
        {...(disabled !== undefined && { isDisabled: disabled })}
        {...(invalid !== undefined && { isInvalid: invalid })}
        {...(required !== undefined && { isRequired: required })}
        {...(readOnly !== undefined && { isReadOnly: readOnly })}
        {...props}
      />
    );
  }
);

RadioGroup.displayName = "RadioGroup";
