import { useContext } from "react";
import { RadioGroupStateContext } from "./RadioGroup";

/**
 * Hook to access the RadioGroup context.
 * Throws an error if used outside of a RadioGroup.
 *
 * @returns The RadioGroupState from the parent RadioGroup
 * @throws Error if used outside of a RadioGroup
 *
 * @example
 * const state = useRadioGroupContext();
 * const isSelected = state.selectedValue === "option1";
 *
 * @example
 * // With custom component name for better error messages
 * const state = useRadioGroupContext();
 * // Throws: "useRadioGroupContext must be used within a RadioGroup"
 */
export function useRadioGroupContext() {
  const state = useContext(RadioGroupStateContext);

  if (!state) {
    throw new Error(`useRadioGroupContext must be used within a RadioGroup`);
  }

  return state;
}
